import { useState } from "react";

function MovieItem({ movie, onDelete, onSelect }) {
    const [isEditing, setIsEditing] = useState(false);
    const [editedTitle, setEditedTitle] = useState(movie.title);

    return (
        <li onClick={() => onSelect(movie)} className="movie-card">
            <img src={movie.poster} alt={movie.title} />

            {isEditing ? (
                <input
                    type="text"
                    value={editedTitle}
                    onChange={(e) => setEditedTitle(e.target.value)}
                    onClick={(e) => e.stopPropagation()} // Prevents popup when clicking input
                />
            ) : (
                <h3>{movie.title}</h3>
            )}

            <button
                onClick={(e) => {
                    e.stopPropagation();
                    setIsEditing(true);
                }}
            >
                Edit
            </button>

            <button
                onClick={(e) => {
                    e.stopPropagation();
                    onDelete(movie.id);
                }}
            >
                Delete
            </button>
        </li>
    );
}

export default MovieItem;
